#include <bits/stdc++.h>
using namespace std;

const long long INF=0x3f3f3f3f3f3f3f3f;

struct Node{
    int val,id;
}a[35];

bool cmp(Node x,Node y){
	return x.val>y.val;
}

int n,m,s[35];
long long f[5005][5005],g[35][5005];
int lg[35][5005],lf[35][5005],ans[35];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i].val);
        a[i].id=i;
    }
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)
        s[i]=s[i-1]+a[i].val;
    memset(g,0x3f,sizeof(g));
    g[0][0]=0;
    for(int i=1;i<=n;i++){
    	memset(f,0x3f,sizeof(f));
        for(int j=i;j<=m;j++){
            for(int k=0;k<i;k++)
                if(g[k][j-i]+1LL*(s[i]-s[k])*k<f[j][1])
                    f[j][1]=g[k][j-i]+1LL*(s[i]-s[k])*k,lf[i][j]=k;
            g[i][j]=f[j][1];
            lg[i][j]=1;
            for(int k=2;k*i<=j;k++){
                f[j][k]=f[j-i][k-1];
                if(f[j][k]<g[i][j])
                    g[i][j]=f[j][k],lg[i][j]=k;
            }
    }
        }
    int num=0;
    for(int i=n,j=m;i && j;){
    	int li=i,lj=j;
        num+=lg[li][lj];
        j-=i*(lg[li][lj]-1);
        for(int k=lf[i][j]+1;k<=i;k++)
            ans[a[k].id] =num;
        i=lf[li][j];
        j-=li;
    }
    printf("%lld\n",g[n][m]);
    for(int i=1;i<=n;i++)
        printf("%d ",ans[i]);
    return 0;
}
